prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?origId ?normId WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  FILTER(STR(?model) CONTAINS "1ad939eef40c461dafae27f75a0586d3" || ?origId = "1ad939eef40c461dafae27f75a0586d3" || ?normId = "1ad939eef40c461dafae27f75a0586d3")
}
LIMIT 10

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?origId ?normId WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  FILTER(STR(?model) = "http://www.semanticweb.org/ontologies/SAP-SAM/Model_1ad939eef40c461dafae27f75a0586d3" || ?origId = "1ad939eef40c461dafae27f75a0586d3" || ?normId = "1ad939eef40c461dafae27f75a0586d3")
}
LIMIT 10

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?choreo ?choreoName (COUNT(DISTINCT ?task) as ?taskCount) (COUNT(DISTINCT ?gw) as ?gatewayCount) WHERE {
  ?choreo a bboExt:Choreography .
  OPTIONAL { ?choreo bbo:name ?choreoName . }
  ?choreo tai:belongsTo ?defs .
  ?defs tai:belongsTo ?model .
  ?model tai:originalId "1ad939eef40c461dafae27f75a0586d3" .

  OPTIONAL { ?task a bboExt:ChoreographyTask . ?task tai:belongsTo ?choreo . }
  OPTIONAL { ?gw a bboExt:ParallelGateway . ?gw tai:belongsTo ?choreo . }
}
GROUP BY ?choreo ?choreoName
